func logEvents(buffer *buffer.Buffer, sizeLimit int, flushInterval int) {
	var mu sync.Mutex
	var currentSize int

	for {
		// Check if buffer is full
		mu.Lock()
		if buffer.Len() >= sizeLimit {
			mu.Unlock()
			// Flush buffer
			buffer.Flush()
			fmt.Println("Buffer flushed")
			continue
		}
		mu.Unlock()

		// Simulate event processing
		event := buffer.Read()
		if event != nil {
			fmt.Printf("Processed event: %v\n", event)
			mu.Lock()
			currentSize += len(event)
			mu.Unlock()
		} else {
			fmt.Println("No event received")
		}

		// Flush periodically
		if currentSize >= sizeLimit {
			mu.Lock()
			buffer.Flush()
			mu.Unlock()
		} else if time.Now().After(time.Now().Add(time.Second * time.Duration(flushInterval))) {
			mu.Lock()
			buffer.Flush()
			mu.Unlock()
		}
	}
}

