vector<pair<int, int>> mergeMeetingTimes(vector<pair<int, int>> intervals) {
    if (intervals.empty()) return {};

    // Sort intervals by start time
    sort(intervals.begin(), intervals.end());

    // Use a priority queue to store intervals
    priority_queue<pair<int, int>, vector<pair<int, int>>, decltype(&pair::first)> pq;

    // Add the first interval to the priority queue
    pq.push(intervals[0]);

    for (size_t i = 1; i < intervals.size(); ++i) {
        // Get the top of the priority queue
        pair<int, int> top = pq.top();
        if (intervals[i].first <= top.second) {
            // Overlapping intervals, merge them
            pq.pop();
            pq.push({top.first, max(top.second, intervals[i].second)});
        } else {
            // No overlap, add to queue
            pq.push(intervals[i]);
        }
    }

    // Extract the merged intervals from the priority queue
    vector<pair<int, int>> merged;
    while (!pq.empty()) {
        merged.push_back(pq.top());
        pq.pop();
    }

    return merged;
}

