    string line;
    while (getline(cin, line)) {
        istringstream iss(line);
        string timestamp;
        string logEntry;
        bool isTimestamp = false;

        while (iss >> logEntry) {
            if (iss.eof()) break;
            if (iss.peek() == ',') {
                iss.ignore();
                iss >> timestamp;
                isTimestamp = true;
            } else {
                if (isTimestamp) {
                    logMap[timestamp].push_back(logEntry);
                    isTimestamp = false;
                } else {
                    logs.push_back({logEntry});
                }
            }
        }
    }

    // Sort logs by timestamp
    for (const auto& [timestamp, entries] : logMap) {
        sort(entries.begin(), entries.end());
        logs.push_back(entries);
    }

    // Output sorted logs
