func rotateArray(arr []int, k int) {
    n := len(arr)
    if n == 0 {
        return
    }
    k %= n
    if k == 0 {
        return
    }
    // Rotate the array to the right by k positions
    for i := 0; i < k; i++ {
        last := arr[n-1]
        for j := n-1; j > 0; j-- {
            arr[j] = arr[j-1]
        }
        arr[0] = last
    }
}

