void organizeSurveyData(vector<pair<int, int>> responses) {
    map<int, int> surveyData;

    for (pair<int, int> response : responses) {
        if (surveyData.find(response.first) != surveyData.end()) {
            // Update existing rating
            surveyData[response.first] = response.second;
        } else {
            // Add new participant
            surveyData[response.first] = response.second;
        }
    }

    // Sort participants by ID
    vector<pair<int, int>> sortedResponses;
    for (const auto& pair : surveyData) {
        sortedResponses.push_back(pair);
    }
    sort(sortedResponses.begin(), sortedResponses.end());

    // Example query
    int queryId = 101;
    if (surveyData.find(queryId) != surveyData.end()) {
        cout << "Rating for participant " << queryId << " is: " << surveyData[queryId] << endl;
    } else {
        cout << "Participant " << queryId << " not found." << endl;
    }
}

