std::vector<double> computeRollingAverages(const std::vector<double>& temperatures, int windowSize) {
    if (windowSize <= 0 || temperatures.empty()) {
        return {};
    }

    std::vector<double> result;
    for (size_t i = 0; i < temperatures.size(); ++i) {
        if (i < windowSize) {
            result.push_back(temperatures[i]);
        } else {
            double average = 0.0;
            for (size_t j = 0; j < windowSize; ++j) {
                if (i - j >= 0) {
                    average += temperatures[i - j];
                }
            }
            average /= windowSize;
            result.push_back(average);
        }
    }

    return result;
}

public class ContactList {
    public static <T> LinkedList<T> mergeContactLists(Collection<LinkedList<T>> contactLists) {
        LinkedList<T> result = new LinkedList<>();
        Set<T> seen = new HashSet<>();

        for (LinkedList<T> list : contactLists) {
            for (T contact : list) {
                if (!seen.contains(contact)) {
                    seen.add(contact);
                    result.add(contact);
                }
            }
        }

        result.sort((o1, o2) -> o1.toString().compareTo(o2.toString()));
        return result;
    }
}

