func processLogFile(filename string) (*log.Logger, error) {
	// Open the log file
	file, err := os.Open(filename)
	if err != nil {
		return nil, err
	}
	defer file.Close()

	// Create a buffer to read the log entries
	reader := bufio.NewReader(file)

	// Create a map to count error occurrences
	errorCount := make(map[string]int)

	// Read each line from the log file
	for {
		line, err := reader.ReadString('\n')
		if err != nil {
			break
		}
		line = strings.TrimSpace(line)

		// Check if the line contains an error pattern
		if strings.Contains(line, "error") {
			errorCount[line]++
		}
	}

	// Create a logger to output the report
	logger, err := log.New(os.Stdout, "Error Report:", log.Lshortfile|log.Ldate|log.Ltime)
	if err != nil {
		return nil, err
	}

	// Print the report
	logger.Printf("Total errors found: %d\n", len(errorCount))
	logger.Printf("Error occurrences:\n")
	for errStr, count := range errorCount {
		logger.Printf("  %s: %d\n", errStr, count)
	}

	return logger, nil
}

func main() {
	// Example usage
	report, err := processLogFile("log.txt")
	if err != nil {
		log.Fatal(err)
	}
	defer report.Close()
}

public class Product {
    private String productId;
    private int quantity;

    // Constructor
    public Product(String productId, int quantity) {
        this.productId = productId;
        this.quantity = quantity;
    }

    // Getters
    public String getProductId() {
        return productId;
    }

    public int getQuantity() {
        return quantity;
    }
}

public class InventoryProcessor {
    public static ArrayList<Product> consolidateInventory(ArrayList<Product> products) {
        // Use a HashMap to aggregate quantities by product ID
        HashMap<String, Integer> productMap = new HashMap<>();
        for (Product product : products) {
            String productId = product.getProductId();
            int quantity = product.getQuantity();
            productMap.put(productId, productMap.getOrDefault(productId, 0) + quantity);
        }

        // Create a new list to store consolidated products
        ArrayList<Product> consolidatedProducts = new ArrayList<>();
        for (Map.Entry<String, Integer> entry : productMap.entrySet()) {
            String productId = entry.getKey();
            int totalQuantity = entry.getValue();
            consolidatedProducts.add(new Product(productId, totalQuantity));
        }

        return consolidatedProducts;
    }
}

