use std::collections::HashSet;

fn detect_cycle_in_graph(graph: &mut Vec<Vec<usize>>, n: usize) -> bool {
    let mut visited = vec![false; n];
    let mut rec_stack = vec![false; n];
    let mut has_cycle = false;

    fn dfs(node: usize, visited: &mut Vec<bool>, rec_stack: &mut Vec<bool>, graph: &Vec<Vec<usize>>) -> bool {
        if rec_stack[node] {
            return true;
        }
        if visited[node] {
            return false;
        }
        visited[node] = true;
        rec_stack[node] = true;

        for neighbor in &graph[node] {
            if dfs(*neighbor, visited, rec_stack, graph) {
                return true;
            }
        }

        rec_stack[node] = false;
        return false;
    }

    for node in 0..n {
        if !visited[node] {
            if dfs(node, &mut visited, &mut rec_stack, graph) {
                has_cycle = true;
                break;
            }
        }
    }

    has_cycle
}
