public static void categorizeStudentScores(List<String> studentScores) {
    HashMap<Integer, List<String>> scoreCategories = new HashMap<>();
    for (String score : studentScores) {
        int scoreInt = Integer.parseInt(score);
        if (scoreInt < 0 || scoreInt > 100) {
            continue; // invalid score, skip
        }
        if (!scoreCategories.containsKey(scoreInt)) {
            scoreCategories.put(scoreInt, new ArrayList<>());
        }
        scoreCategories.get(scoreInt).add(score);
    }
}

public class MeetingScheduler {
    public static ArrayList<Meeting> organizeMeetings(List<Meeting> meetings) {
        PriorityQueue<Meeting> priorityQueue = new PriorityQueue<>(Comparator.reverseOrder());
        ArrayList<Meeting> processedMeetings = new ArrayList<>();

        for (Meeting meeting : meetings) {
            priorityQueue.add(meeting);
        }

        while (!priorityQueue.isEmpty()) {
            Meeting currentMeeting = priorityQueue.poll();
            processedMeetings.add(currentMeeting);
        }

        return processedMeetings;
    }
}

