    int grades[5]; // Assuming 5 subjects
};

void analyzeStudentPerformance(Student students[], int size) {
    for (int i = 0; i < size; i++) {
        int sum = 0;
        for (int j = 0; j < 5; j++) {
            sum += students[i].grades[j];
        }
        int average = sum / 5;
        cout << "Student " << students[i].name << " average grade: " << average << endl;
    }
}

