using namespace std;

int deduplicateEmailAddresses(vector<string>& emails) {
    unordered_set<string> uniqueEmails;
    vector<string> result;
    int duplicatesCount = 0;

    for (const auto& email : emails) {
        if (uniqueEmails.find(email) != uniqueEmails.end()) {
            duplicatesCount++;
            continue;
        }
        uniqueEmails.insert(email);
        result.push_back(email);
    }

    return duplicatesCount;
}

int main() {
    vector<string> emails = {"a@example.com", "b@example.com", "a@example.com", "c@example.com"};
    int count = deduplicateEmailAddresses(emails);
    cout << "Number of duplicates removed: " << count << endl;
    return 0;
}

def track_online_orders(orders):
    order_dict = {}  # Dictionary to store order statuses
    for order in orders:
        order_id, status = order
        if order_id in order_dict:
            order_dict[order_id] = status  # Update existing order
        else:
            order_dict[order_id] = status  # Insert new order
    return order_dict
